const body=($('Webhook').first().json.body)||{};
const ids=Array.isArray(body.ids)?body.ids.filter(Boolean):[];
const PB_URL=($('Config').first().json.pbUrl||'').replace(/\/+$/,'');
const token=$('PB Auth').first().json.token; const pbH={Authorization:token};
const sd=$getWorkflowStaticData('global'); const now=new Date().toISOString();
let jobId=''; try{ const j=await this.helpers.httpRequest({method:'POST',url:PB_URL+'/api/collections/job_runs/records',headers:pbH,body:{kind:'batch-enrich',label:'Resolve club websites',status:'running',total:ids.length,processed:0,started:now},json:true}); jobId=j.id; }catch(e){}
sd.jobId=jobId; sd.jobProcessed=0; sd.jobTotal=ids.length;
if(!ids.length && jobId){ try{ await this.helpers.httpRequest({method:'PATCH',url:PB_URL+'/api/collections/job_runs/records/'+jobId,headers:pbH,body:{status:'done',finished:now,processed:0,message:'Nothing to process'},json:true}); }catch(e){} sd.jobId=''; }
return ids.map(id=>({json:{id}}));

const sd=$getWorkflowStaticData('global');
if(sd.jobId){ const PB_URL=($('Config').first().json.pbUrl||'').replace(/\/+$/,''); const token=$('PB Auth').first().json.token; const pbH={Authorization:token};
  try{ sd.jobProcessed=(sd.jobProcessed||0)+$('Loop').all().length; await this.helpers.httpRequest({method:'PATCH',url:PB_URL+'/api/collections/job_runs/records/'+sd.jobId,headers:pbH,body:{processed:Math.min(sd.jobProcessed,sd.jobTotal||sd.jobProcessed),message:'processing…'},json:true}); }catch(e){} }
return $input.all();

